-- W1.6 questions batch 245/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-5ff21eeb-moex-00022', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '成年之甲，父母雙亡，惟因心智缺陷，經法院為監護宣告，並指定乙女為監護人。治癒後，法院 尚未撤銷監護宣告，甲、乙依法結婚。下列敘述何者正確？', '["甲、乙婚姻無效", "甲得向法院請求撤銷婚姻", "法院依職權撤銷婚姻", "甲、乙婚姻有效，雙方均不得請求撤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00023', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '丙成年後得本生父母甲、乙之同意，由丁、戊共同收養。嗣後丁遇車禍身亡。下列關於收養終止 之敘述，何者錯誤？', '["丁、戊僅限於離婚之事由，丙始得單獨與戊合意終止收養", "戊對丙為虐待者，丙亦得聲請法院宣告終止與戊之收養關係", "丙與戊合意終止收養後，丙亦得聲請法院許可終止與丁之收養關係", "戊因與丙終止收養而生活陷於困難，原則上得請求丙給與相當之金額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00024', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲女未婚生子乙，乙之生父為丙。下列關於認領之敘述，何者正確？', '["甲得請求丙認領乙，但甲應於乙出生後5年間為之", "丙得主動認領乙，但丙應自知悉乙為其非婚生子女之時起7年內為之", "丙仍活著時，乙得請求丙認領，但乙應於成年後2年間為之", "設丙已死亡，丙有繼承人，乙得向丙之繼承人提起強制認領之訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00025', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '被繼承人甲與乙係夫妻，乙妻早於甲夫死亡，甲死亡後留有遺產新臺幣（下同）1,500萬元，甲、 乙生前育有2子丙、丁；丙於甲死亡後依法拋棄繼承，丙有1女戊，另乙婚前即育有1子己，甲、 乙婚後，甲未收養己。下列何人有繼承權或代位繼承權，其應繼財產若干？', '["丁有繼承權，戊及己有代位繼承權；丁、戊、己各得500萬元", "丁有繼承權，戊有代位繼承權，己無代位繼承權；丁、戊各得750萬元", "丁有繼承權，戊無代位繼承權，己有代位繼承權；丁、己各得750萬元", "丁為唯一繼承人，得繼承遺產之全部1,500萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00026', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列何種情況，繼承人喪失其繼承權？', '["繼承人變造遺囑中所指定之未成年子女監護人", "被繼承人自書遺囑並簽名，繼承人補填其未記明之年月日", "繼承人對被繼承人有重大侮辱之行為，經被繼承人於未經公證之書面中表示使其喪失繼承權", "繼承人故意殺害被繼承人，被繼承人未致死，經法院為免訴之判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00027', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-114-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲未婚無子，父母、祖父母均已死亡。有一兄，但已死亡。甲生前扶養其兄之未成年子乙。甲死 亡時，留有新臺幣（下同）200萬元之現金，但對丙負有100萬元債務。甲立遺囑遺贈丁100萬 元。乙經親屬會議決議酌給50萬元。乙、丙、丁得自甲之遺產，分別獲得多少金額？', '["乙0元、丙100萬元、丁100萬元", "乙50萬元、丙100萬元、丁50萬元", "乙50萬元、丙50萬元、丁100萬元", "乙25萬元、丙100萬元、丁75萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "c3d287d292c9", "answer_pdf_sha1": "5eea37b6cb02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00028', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-113-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'essay', '甲旅行社租用乙交通公司之遊覽車出團花蓮太魯閣 2 日遊，由靠行乙營
業之丙駕駛，該遊覽車身並有「乙交通公司」字樣，途中不慎發生車禍
翻車，造成該旅行團員丁身體受傷。問丁得向甲、乙及丙請求何種權利？
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00029', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-113-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'essay', '甲原住民向乙原住民承租 A原住民保留地做造林之用，雙方訂立租賃契
約，約定得在 A地採伐杉木。甲除植木於 A地外，亦過失越界在同屬乙
之 B原住民保留地植木。甲在開始採伐林木前，B地被乙售與非原住民
丙，借名登記於原住民丁，並已辦理所有權移轉登記。甲開採後取得在
B 地所種之杉木，價值 10 萬元。問丙得否對甲主張該杉木之所有權？
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00030', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-113-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '附條件之買賣契約當事人，於條件成否未定前，損害相對人因條件成就所應得利益之行為者，有 何法律上之效力？', '["條件成就時，始負賠償損害之責任", "損害發生時，條件尚未成就，法律行為失效", "立即負有賠償損害之責任", "相對人得解除契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00031', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-113-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列何種契約，屬於若無書面即屬無效之契約？', '["人事保證", "和解", "合夥", "物品運送"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL)
